  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\nenum UserRole {\n  SUPER_ADMIN\n  OWNER\n  MANAGER\n  STAFF\n  SALES\n  FINANCE\n}\n\nenum CustomerStatus {\n  LEAD\n  PROSPECT\n  CUSTOMER\n  VIP\n  INACTIVE\n  LOST\n}\n\nenum OrderStatus {\n  DRAFT\n  PENDING\n  CONFIRMED\n  PROCESSING\n  COMPLETED\n  DELIVERED\n  CANCELLED\n  REFUNDED\n}\n\nenum InvoiceStatus {\n  DRAFT\n  SENT\n  PARTIALLY_PAID\n  PAID\n  OVERDUE\n  CANCELLED\n}\n\nenum MessageType {\n  TEXT\n  IMAGE\n  VIDEO\n  AUDIO\n  DOCUMENT\n  TEMPLATE\n  SYSTEM\n}\n\nenum ConversationStatus {\n  OPEN\n  PENDING\n  RESOLVED\n  CLOSED\n}\n\nenum PaymentMethod {\n  CASH\n  TRANSFER\n  QRIS\n  EWALLET\n  GATEWAY\n}\n\nenum AutomationTrigger {\n  NEW_CUSTOMER\n  NEW_MESSAGE\n  NEW_ORDER\n  INVOICE_OVERDUE\n  PAYMENT_RECEIVED\n}\n\nmodel Tenant {\n  id        String  @id @default(uuid())\n  name      String\n  domain    String? @unique\n  plan      String\n  is_active Boolean @default(true)\n\n  users     User[]\n  customers Customer[]\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  @@map(\"tenants\")\n}\n\nmodel User {\n  id         String    @id @default(uuid())\n  tenant_id  String\n  tenant     Tenant    @relation(fields: [tenant_id], references: [id])\n  name       String\n  email      String\n  password   String\n  role       UserRole\n  is_active  Boolean   @default(true)\n  last_login DateTime?\n  created_at DateTime  @default(now())\n  updated_at DateTime  @updatedAt\n\n  @@index([tenant_id])\n  @@index([email])\n  @@map(\"users\")\n}\n\nmodel Customer {\n  id           String         @id @default(uuid())\n  tenant_id    String\n  tenant       Tenant         @relation(fields: [tenant_id], references: [id])\n  name         String\n  phone        String\n  email        String?\n  address      String?\n  status       CustomerStatus @default(LEAD)\n  total_orders Int            @default(0)\n  total_spent  Float          @default(0)\n  last_contact DateTime?\n  deleted_at   DateTime?\n  created_at   DateTime       @default(now())\n  updated_at   DateTime       @updatedAt\n\n  tags          CustomerTag[]\n  conversations Conversation[]\n  orders        Order[]\n\n  @@index([tenant_id])\n  @@index([phone])\n  @@map(\"customers\")\n}\n\nmodel CustomerTag {\n  id          String   @id @default(uuid())\n  tenant_id   String\n  customer_id String\n  customer    Customer @relation(fields: [customer_id], references: [id])\n  tag         String\n\n  @@index([tenant_id])\n  @@map(\"customer_tags\")\n}\n\nmodel Conversation {\n  id           String             @id @default(uuid())\n  tenant_id    String\n  customer_id  String\n  customer     Customer           @relation(fields: [customer_id], references: [id])\n  assigned_to  String?\n  status       ConversationStatus @default(OPEN)\n  last_message String?\n  unread_count Int                @default(0)\n  created_at   DateTime           @default(now())\n  updated_at   DateTime           @updatedAt\n\n  messages Message[]\n\n  @@index([tenant_id])\n  @@index([customer_id])\n  @@map(\"conversations\")\n}\n\nmodel Message {\n  id              String       @id @default(uuid())\n  tenant_id       String\n  conversation_id String\n  conversation    Conversation @relation(fields: [conversation_id], references: [id])\n  sender_id       String?\n  type            MessageType\n  content         String\n  media_url       String?\n  status          String       @default(\"sent\")\n  created_at      DateTime     @default(now())\n\n  @@index([tenant_id])\n  @@index([conversation_id])\n  @@map(\"messages\")\n}\n\nmodel Order {\n  id           String      @id @default(uuid())\n  tenant_id    String\n  customer_id  String\n  customer     Customer    @relation(fields: [customer_id], references: [id])\n  order_number String\n  status       OrderStatus @default(PENDING)\n  subtotal     Float\n  tax          Float\n  discount     Float\n  total        Float\n  created_at   DateTime    @default(now())\n  updated_at   DateTime    @updatedAt\n\n  order_items OrderItem[]\n  invoices    Invoice[]\n\n  @@index([tenant_id])\n  @@index([order_number])\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id        String @id @default(uuid())\n  tenant_id String\n  order_id  String\n  order     Order  @relation(fields: [order_id], references: [id])\n  name      String\n  quantity  Int\n  price     Float\n\n  @@index([tenant_id])\n  @@map(\"order_items\")\n}\n\nmodel Invoice {\n  id             String        @id @default(uuid())\n  tenant_id      String\n  order_id       String\n  order          Order         @relation(fields: [order_id], references: [id])\n  invoice_number String\n  status         InvoiceStatus\n  total          Float\n  paid_amount    Float         @default(0)\n  due_date       DateTime?\n  created_at     DateTime      @default(now())\n\n  payments Payment[]\n\n  @@index([tenant_id])\n  @@map(\"invoices\")\n}\n\nmodel Payment {\n  id         String        @id @default(uuid())\n  tenant_id  String\n  invoice_id String\n  invoice    Invoice       @relation(fields: [invoice_id], references: [id])\n  method     PaymentMethod\n  amount     Float\n  created_at DateTime      @default(now())\n\n  @@index([tenant_id])\n  @@map(\"payments\")\n}\n\nmodel Automation {\n  id         String   @id @default(uuid())\n  tenant_id  String\n  name       String\n  trigger    String\n  is_active  Boolean  @default(true)\n  created_at DateTime @default(now())\n\n  @@map(\"automations\")\n}\n\nmodel Task {\n  id          String    @id @default(uuid())\n  tenant_id   String\n  title       String\n  description String?\n  assigned_to String?\n  status      String    @default(\"pending\")\n  due_date    DateTime?\n  created_at  DateTime  @default(now())\n\n  @@index([tenant_id])\n  @@map(\"tasks\")\n}\n\nmodel Notification {\n  id         String   @id @default(uuid())\n  tenant_id  String\n  user_id    String\n  title      String\n  message    String\n  is_read    Boolean  @default(false)\n  created_at DateTime @default(now())\n\n  @@index([tenant_id])\n  @@map(\"notifications\")\n}\n\nmodel AuditLog {\n  id         String   @id @default(uuid())\n  tenant_id  String\n  user_id    String\n  action     String\n  resource   String\n  ip_address String?\n  metadata   Json?\n  created_at DateTime @default(now())\n\n  @@index([tenant_id])\n  @@map(\"audit_logs\")\n}\n\nmodel Subscription {\n  id         String    @id @default(uuid())\n  tenant_id  String\n  plan       String\n  status     String\n  start_date DateTime\n  end_date   DateTime?\n  created_at DateTime  @default(now())\n\n  @@map(\"subscriptions\")\n}\n\nmodel AiAgentConfig {\n  id            String  @id @default(uuid())\n  tenant_id     String  @unique\n  is_active     Boolean @default(false)\n  system_prompt String  @default(\"Anda adalah asisten AI toko online UMKM. Jawab pertanyaan pelanggan dengan ramah, singkat, dan informatif.\")\n  catalog_data  String?\n\n  // API Keys\n  gemini_api_key String?\n  groq_api_key   String?\n  cohere_api_key String?\n  openrouter_key String?\n\n  primary_provider String @default(\"gemini\") // gemini, groq, cohere, openrouter\n  temperature      Float  @default(0.7)\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  @@map(\"ai_agent_configs\")\n}\n\nmodel AiRouterLog {\n  id            String   @id @default(uuid())\n  tenant_id     String\n  provider      String // gemini, groq, cohere, openrouter, dll.\n  fallback_used Boolean  @default(false)\n  status        String // success, failed\n  latency_ms    Int      @default(0)\n  error_message String?\n  created_at    DateTime @default(now())\n\n  @@index([tenant_id])\n  @@map(\"ai_router_logs\")\n}\n",
